  "suggestions": {
    "claude_md_additions": [
      {
        "addition": "This is a macOS/Swift project (BauhasClock screensaver). Always use Arabic numerals (not Roman numerals) for clock faces unless explicitly told otherwise. Reference images are the source of truth for visual styling.",
