   864→    function updateHourHistogram(offsetFromPT) {
   865→      const periods = [
   866→        { label: "Morning (6-12)", range: [6,7,8,9,10,11] },
   867→        { label: "Afternoon (12-18)", range: [12,13,14,15,16,17] },
