   894→        fill.style.background = '#8b5cf6';
   895→        track.appendChild(fill);
   896→        const value = document.createElement('div');
   897→        value.className = 'bar-value';
   898→        value.textContent = p.count;
   899→        row.appendChild(label);
   900→        row.appendChild(track);
   901→        row.appendChild(value);
   902→        container.appendChild(row);
   903→      });
   904→    }
